56	// package. Production code always goes through NewDoHResolver, which passes
57	// roots=nil and gets tls.Config's default (the system pool).
58	func newDoHResolver(rawURL string, roots *x509.CertPool) (*DoHResolver, error) {
59		parsed, err := url.Parse(rawURL)
60		if err != nil {
61			return nil, fmt.Errorf("dnsresolve: invalid DoH URL %q: %w", rawURL, err)
