69			// environment-configured (HTTP_PROXY/HTTPS_PROXY) proxy — a DoH
70			// resolver silently redirected through an unexpected intermediary
71			// would defeat the point of choosing a specific trusted provider.
72			Proxy: nil,
73			TLSClientConfig: &tls.Config{
74				RootCAs:    roots,
75				MinVersion: tls.VersionTLS12,
76			},
77			// HTTP/2 ok: Go only auto-negotiates h2 over a custom
78			// TLSClientConfig when this is set explicitly.
79			ForceAttemptHTTP2: true,
80		}
