153		}
154		defer resp.Body.Close()
155	
156		if resp.StatusCode != http.StatusOK {
157			return nil, 0, false, &StatusError{URL: d.url, StatusCode: resp.StatusCode}
158		}
159	
160		body, err := io.ReadAll(resp.Body)
161		if err != nil {
162			if isTimeoutErr(err) {
163				return nil, 0, false, &TimeoutError{URL: d.url, Err: err}
164			}
165			return nil, 0, false, &MalformedResponseError{URL: d.url, Err: err}
