28	func newDoHTestResolver(t *testing.T, srv *httptest.Server, path string) *DoHResolver {
29		t.Helper()
30		pool := newCertPoolFromServer(t, srv)
31		r, err := newDoHResolver(srv.URL+path, pool)
32		if err != nil {
33			t.Fatalf("newDoHResolver: unexpected error: %v", err)
34		}
