38	func readDoHQuestion(t *testing.T, r *http.Request) (dnsmessage.Message, dnsmessage.Type) {
39		t.Helper()
40		if r.Method != http.MethodPost {
41			t.Fatalf("DoH request method = %s, want POST", r.Method)
